<script>
const form=document.getElementById('post-wizard'),projectSelect=document.getElementById('project_id'),platform=document.getElementById('platform'),target=document.getElementById('social_page_id'),message=document.getElementById('message'),media=document.getElementById('media'),action=document.getElementById('action'),timezone=document.getElementById('timezone'),scheduledDate=document.getElementById('scheduled_date'),scheduledTime=document.getElementById('scheduled_time');let step={{ $initialStep }},projectPages=[];
// New posts start in the visitor's actual browser timezone instead of an inherited UTC fallback.
if (!{{ $editing ? 'true' : 'false' }} && (!timezone.value || timezone.value === 'UTC')) { try { timezone.value = Intl.DateTimeFormat().resolvedOptions().timeZone || 'UTC'; } catch (error) {} }
const config={facebook:{limit:63206,types:['Post','Image','Video','Reel'],guide:'Recommended image: 1200 × 630. Videos up to 10GB.'},instagram:{limit:2200,types:['Image','Reel','Carousel'],guide:'Image: 1080 × 1080. Caption limit: 2,200 characters.'},linkedin:{limit:3000,types:['Post','Image','Video'],guide:'Character limit: 3,000.'},twitter:{limit:280,types:['Post','Image','Video'],guide:'Standard posts support up to 280 characters.'},tiktok:{limit:2200,types:['Video'],guide:'Use a 9:16 video and a concise caption.'},youtube:{limit:5000,types:['Video'],guide:'A video is required for YouTube publishing.'}};
function escapeHtml(value){const div=document.createElement('div');div.textContent=value||'';return div.innerHTML}function current(){return config[platform.value]||config.facebook}function feedback(field){let el=document.getElementById(`${field}-error`);if(!el){el=document.createElement('div');el.id=`${field}-error`;el.className='invalid-feedback';const input=document.getElementById(field);(input?.parentNode||document.getElementById('platform-picker')).append(el)}return el}function clearError(field){const input=document.getElementById(field);input?.classList.remove('is-invalid');if(field==='platform')document.getElementById('platform-picker').classList.remove('is-invalid');feedback(field).textContent=''}function setError(field,text){const input=document.getElementById(field);if(input)input.classList.add('is-invalid');if(field==='platform')document.getElementById('platform-picker').classList.add('is-invalid');feedback(field).textContent=text;return input||document.getElementById('platform-picker')}
function selectedAction(){return document.querySelector('[name="publish_option"]:checked')?.value||''}function validateStep(number){const checks={1:[['project_id',projectSelect.value,'Please select a project.']],2:[['platform',platform.value,'Please select a platform.']],3:[['social_page_id',target.value,'Please select an account or page.']],5:[['message',message.value.trim(),'Caption is required.']]};if(number===6){checks[6]=[['action',selectedAction(),'Please choose a publish option.']];if(selectedAction()==='schedule')checks[6].push(['scheduled_date',scheduledDate.value,'Schedule date is required.'],['scheduled_time',scheduledTime.value,'Schedule time is required.'],['timezone',timezone.value,'Timezone is required.']);if(selectedAction()==='schedule'&&scheduledDate.value&&scheduledTime.value&&timezone.value){const today=zoneDate(timezone.value);if(scheduledDate.value<today||scheduledDate.value===today&&scheduledTime.value<=zoneTime(timezone.value))checks[6].push(['scheduled_time',false,'You cannot schedule a post in the past. Please select a future date and time.'])}}const failures=(checks[number]||[]).filter(([,value])=>!value);(checks[number]||[]).forEach(([field,value])=>value&&clearError(field));failures.forEach(([field,,text])=>setError(field,text));return failures[0]?.[0]||null}
function show(newStep,validate=true){if(newStep>step&&validate){const invalid=validateStep(step);if(invalid){const field=document.getElementById(invalid)||document.querySelector('.wizard-platform-card:not(.d-none)');field?.focus();field?.scrollIntoView({behavior:'smooth',block:'center'});return}}step=newStep;document.querySelectorAll('.wizard-step').forEach(s=>s.classList.toggle('d-none',+s.dataset.step!==step));document.querySelectorAll('.wizard-progress-item').forEach(p=>p.classList.toggle('active',+p.dataset.progress<=step));document.getElementById('previous-step').classList.toggle('d-none',step===1);document.getElementById('next-step').classList.toggle('d-none',step===7);document.getElementById('submit-post').classList.toggle('d-none',step!==7);document.getElementById('next-step').disabled=step===2&&availablePlatforms().size===0;if(step===7)review();window.scrollTo({top:0,behavior:'smooth'})}
function renderDestinations(){const instagram=platform.value==='instagram',selected=target.value,pages=projectPages.filter(p=>p.provider===platform.value||(instagram&&p.provider==='facebook'&&p.instagram_business_id));target.innerHTML='<option value="">Select profile/page</option>'+pages.map(p=>`<option value="${p.id}">${instagram?`Facebook Page: ${escapeHtml(p.name)} → Instagram: @${escapeHtml(p.instagram_username||'Business Account')}`:escapeHtml(p.name)}</option>`).join('');if([...target.options].some(o=>o.value===selected))target.value=selected;document.getElementById('destination-label').innerHTML=`${instagram?'Facebook Page':'Page / Profile'} <span class="required-indicator">*</span>`;document.getElementById('destination-help').textContent=instagram?'Select the Facebook Page; its linked Instagram Business Profile will be selected automatically.':'Choose the connected destination for this post.'}
function availablePlatforms(){const providers=new Set;projectPages.forEach(page=>{providers.add(page.provider);if(page.provider==='facebook'&&page.instagram_business_id)providers.add('instagram')});return providers}function renderAvailablePlatforms(){const available=availablePlatforms();document.querySelectorAll('.wizard-platform-card').forEach(card=>card.classList.toggle('d-none',!available.has(card.dataset.platform)));document.getElementById('platform-empty').classList.toggle('d-none',available.size>0);if(platform.value&&!available.has(platform.value))platform.value='';document.getElementById('next-step').disabled=step===2&&available.size===0}function renderPlatform(){renderAvailablePlatforms();const settings=current();document.querySelectorAll('.wizard-platform-card').forEach(card=>card.classList.toggle('active',card.dataset.platform===platform.value));document.getElementById('content-types').innerHTML=settings.types.map((type,index)=>`<label class="content-type-card"><input type="radio" name="content_type" value="${type.toLowerCase()}" ${index===0?'checked':''}><span><i class="bi bi-${type==='Video'||type==='Reel'?'play-circle':type==='Image'?'image':'chat-square-text'}"></i>${type}</span></label>`).join('');document.getElementById('platform-guidelines').innerHTML=`<strong>${platform.value?platform.value[0].toUpperCase()+platform.value.slice(1):'Platform'} guidelines</strong><p class="mb-0 mt-1">${settings.guide}</p>`;renderDestinations();updateCounter();updatePreview()}
function updateCounter(){const limit=current().limit,length=message.value.length,counter=document.getElementById('caption-counter');counter.textContent=`${length} / ${limit}`;counter.className=length>limit?'text-danger':'text-muted'}function updatePreview(){document.getElementById('preview-message').textContent=message.value||'Your caption will appear here.';document.getElementById('preview-dot').className=`platform-dot platform-${platform.value||'facebook'}`;const selected=target.options[target.selectedIndex];document.getElementById('preview-name').textContent=selected&&selected.value?selected.text.replace(/^Facebook Page: /,'').split(' → ')[0]:'Your profile';if(step===6)review()}function review(){const option=selectedAction(),selected=target.options[target.selectedIndex],files=[...media.files],schedule=option==='schedule'?`${scheduledDate.value||'No date'} at ${scheduledTime.value||'No time'} (${timezone.value})`:option==='publish'?'Publish immediately':'Save as a draft';document.getElementById('review-summary').innerHTML=[['Project',projectSelect.options[projectSelect.selectedIndex]?.text],['Platform',platform.value],['Destination',selected?.text]].map(([label,value])=>`<div><span>${escapeHtml(label)}</span><strong>${escapeHtml(value)}</strong></div>`).join('');const reviewPreview=document.getElementById('review-live-preview'),previewMedia=document.getElementById('preview-media');reviewPreview.innerHTML=`<div class="preview-label">What will be published</div><div class="preview-head"><span class="platform-dot platform-${escapeHtml(platform.value||'facebook')}"></span><strong>${escapeHtml(selected?.text||'Your profile')}</strong></div>${previewMedia?.innerHTML?`<div class="review-preview-media">${previewMedia.innerHTML}</div>`:''}<p class="mb-3 text-break">${escapeHtml(message.value||'Your caption will appear here.')}</p><div class="review-publish-time"><strong>${option==='schedule'?'Scheduled':'Publishing'}</strong><span>${escapeHtml(schedule)}</span></div>`}
function zoneParts(zone){return Object.fromEntries(new Intl.DateTimeFormat('en-CA',{timeZone:zone,year:'numeric',month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit',hourCycle:'h23'}).formatToParts(new Date()).filter(p=>p.type!=='literal').map(p=>[p.type,p.value]))}function zoneDate(zone){try{const p=zoneParts(zone);return `${p.year}-${p.month}-${p.day}`}catch{return new Date().toISOString().slice(0,10)}}function zoneTime(zone){try{const p=zoneParts(zone);return `${p.hour}:${p.minute}`}catch{return new Date().toTimeString().slice(0,5)}}function updateScheduleLimits(){const today=zoneDate(timezone.value||'UTC');scheduledDate.min=today;scheduledTime.min=scheduledDate.value===today?zoneTime(timezone.value||'UTC'):''}function updateTimes(){try{const now=new Date(),zone=timezone.value||'UTC';document.getElementById('local-time').textContent=`${zone}: ${new Intl.DateTimeFormat(undefined,{dateStyle:'medium',timeStyle:'short',timeZone:zone}).format(now)}`;document.getElementById('utc-time').textContent=`UTC: ${new Intl.DateTimeFormat(undefined,{dateStyle:'medium',timeStyle:'short',timeZone:'UTC'}).format(now)} UTC`;updateScheduleLimits()}catch(e){document.getElementById('local-time').textContent='Enter a valid IANA timezone.'}}
let previewUrls=[];function renderMediaPreview(files=[]){const preview=document.getElementById('preview-media');previewUrls.forEach(URL.revokeObjectURL);previewUrls=[];preview.replaceChildren();preview.style.backgroundImage='';files=Array.isArray(files)?files:[files].filter(Boolean);if(!files.length){preview.classList.add('d-none');return}files.forEach(file=>{const url=URL.createObjectURL(file),element=document.createElement(file.type.startsWith('video/')?'video':'img');previewUrls.push(url);element.src=url;element.className='preview-media-file';if(element.tagName==='VIDEO'){element.controls=true;element.preload='metadata';element.playsInline=true;element.setAttribute('aria-label',`Video preview: ${file.name}`)}else element.alt=`Image preview: ${file.name}`;preview.append(element)});preview.classList.remove('d-none')}
projectPages=Array.from(target.options).slice(1).map(o=>({id:o.value,provider:o.dataset.provider,name:o.textContent.trim(),instagram_business_id:o.dataset.instagram==='1',instagram_username:o.dataset.instagramUsername}));document.querySelectorAll('.wizard-platform-card').forEach(card=>card.addEventListener('click',()=>{platform.value=card.dataset.platform;clearError('platform');renderPlatform()}));projectSelect.addEventListener('change',async()=>{clearError('project_id');target.innerHTML='<option>Loading profiles/pages…</option>';const response=await fetch(`{{ route('posts.pages') }}?project_id=${encodeURIComponent(projectSelect.value)}`,{headers:{Accept:'application/json'}});projectPages=response.ok?await response.json():[];renderPlatform()});target.addEventListener('change',()=>{clearError('social_page_id');updatePreview()});message.addEventListener('input',()=>{clearError('message');updateCounter();updatePreview()});document.querySelectorAll('[data-insert]').forEach(button=>button.addEventListener('click',()=>{message.value+=`${message.value?' ':''}${button.dataset.insert}`;message.focus();updateCounter();updatePreview()}));media.addEventListener('change',()=>{const files=[...media.files];document.getElementById('media-thumbnails').innerHTML=files.map(file=>`<span class="media-chip"><i class="bi bi-file-earmark"></i> ${escapeHtml(file.name)}</span>`).join('');renderMediaPreview(files[0])});window.addEventListener('beforeunload',()=>{if(previewUrl)URL.revokeObjectURL(previewUrl)});document.querySelectorAll('[name="publish_option"]').forEach(input=>input.addEventListener('change',()=>{action.value=input.value;document.getElementById('schedule-fields').classList.toggle('d-none',input.value!=='schedule');clearError('action')}));[scheduledDate,scheduledTime,timezone].forEach(input=>input.addEventListener('change',()=>{clearError(input.id);updateTimes()}));document.getElementById('next-step').addEventListener('click',()=>show(step+1));document.getElementById('previous-step').addEventListener('click',()=>show(step-1));form.addEventListener('submit',event=>{action.value=selectedAction();for(let number=1;number<=6;number++){const invalid=validateStep(number);if(invalid){event.preventDefault();show(number,false);const field=document.getElementById(invalid)||document.querySelector('.wizard-platform-card:not(.d-none)');field?.focus();field?.scrollIntoView({behavior:'smooth',block:'center'});return}}});renderPlatform();document.getElementById('schedule-fields').classList.toggle('d-none',selectedAction()!=='schedule');updateTimes();show(step,false);const firstInvalid=form.querySelector('.is-invalid');if(firstInvalid)setTimeout(()=>{firstInvalid.focus();firstInvalid.scrollIntoView({behavior:'smooth',block:'center'})},100);
</script>
<script>
var activePlatform=platform.value;
var instagramContentTypes={image:{label:'Image Post',icon:'image',accept:'image/jpeg,image/png',multiple:false,title:'Drop one image here',help:'JPG or PNG image'},carousel:{label:'Carousel',icon:'images',accept:'image/jpeg,image/png,video/mp4,video/quicktime',multiple:true,title:'Drop carousel images or videos here',help:'JPG, PNG, MP4, or MOV — 2 to 10 items'},reel:{label:'Reel',icon:'play-circle',accept:'video/mp4,video/quicktime',multiple:false,title:'Drop one reel video here',help:'MP4 or MOV video'}};
function selectedInstagramContentType(){return document.querySelector('[name="content_type"]:checked')?.value||''}
function clearMediaForPlatform(){media.value='';document.getElementById('media-thumbnails').replaceChildren();renderMediaPreview();clearError('media')}
function renderInstagramContentType(){var isInstagram=platform.value==='instagram',isTikTok=platform.value==='tiktok',section=document.getElementById('instagram-content-type'),upload=document.getElementById('media-upload-section'),types=document.getElementById('content-types');section.classList.toggle('d-none',!isInstagram);if(!isInstagram){types.replaceChildren();upload.classList.remove('d-none');if(isTikTok){media.accept='video/mp4,video/quicktime,video/webm';media.multiple=false;document.getElementById('media-upload-title').textContent='Drop one TikTok video here';document.getElementById('media-upload-help').textContent='One MP4, MOV, or WebM video is required'}else{media.accept='image/*,video/*';media.multiple=true;document.getElementById('media-upload-title').textContent='Drop images or videos here';document.getElementById('media-upload-help').textContent='JPG, PNG, WEBP, GIF, MP4, MOV, AVI, WEBM'}return}types.innerHTML=Object.entries(instagramContentTypes).map(([value,type])=>`<label class="content-type-card"><input type="radio" name="content_type" value="${value}"><span><i class="bi bi-${type.icon}"></i>${type.label}</span></label>`).join('');upload.classList.add('d-none');document.getElementById('content_type-error').textContent=''}
function configureInstagramUpload(){var type=instagramContentTypes[selectedInstagramContentType()],upload=document.getElementById('media-upload-section');if(!type){upload.classList.add('d-none');return}upload.classList.remove('d-none');media.accept=type.accept;media.multiple=type.multiple;document.getElementById('media-upload-title').textContent=type.title;document.getElementById('media-upload-help').textContent=type.help;document.getElementById('content_type-error').textContent=''}
document.querySelectorAll('.wizard-platform-card').forEach(card=>card.addEventListener('click',()=>{if(activePlatform!==platform.value){clearMediaForPlatform();activePlatform=platform.value}renderInstagramContentType();updatePreview()}));
document.getElementById('content-types').addEventListener('change',()=>{clearMediaForPlatform();configureInstagramUpload()});
validateStep=function(number){var checks={1:[['project_id',projectSelect.value,'Please select a project.']],2:[['platform',platform.value,'Please select a platform.']],3:[['social_page_id',target.value,'Please select an account or page.']],4:[['message',message.value.trim(),'Caption is required.']]};if(number===4&&platform.value==='instagram'){var type=selectedInstagramContentType(),files=[...media.files];checks[4].push(['content_type',type,'Choose an Instagram content type.'],['media',files.length,'Add media for this Instagram post.']);if(type==='image'&&(files.length!==1||files.some(file=>!file.type.startsWith('image/'))))checks[4].push(['media',false,'An image post requires exactly one image.']);if(type==='reel'&&(files.length!==1||files.some(file=>!file.type.startsWith('video/'))))checks[4].push(['media',false,'A reel requires exactly one video.']);if(type==='carousel'&&(files.length<2||files.length>10))checks[4].push(['media',false,'A carousel requires between 2 and 10 media items.'])}if(number===4&&platform.value==='tiktok'){var tikTokFiles=[...media.files];checks[4].push(['media',tikTokFiles.length===1&&tikTokFiles[0].type.match(/^video\/(mp4|quicktime|webm)$/),'A TikTok post requires exactly one MP4, MOV, or WebM video.'])}if(number===5){checks[5]=[['action',selectedAction(),'Please choose a publish option.']];if(selectedAction()==='schedule')checks[5].push(['scheduled_date',scheduledDate.value,'Schedule date is required.'],['scheduled_time',scheduledTime.value,'Schedule time is required.'],['timezone',timezone.value,'Timezone is required.'])}var failed=(checks[number]||[]).find(([,value])=>!value);if(failed){var error=document.getElementById(`${failed[0]}-error`);if(error)error.textContent=failed[2];document.getElementById(failed[0])?.classList.add('is-invalid');return failed[0]}(checks[number]||[]).forEach(([field])=>clearError(field));return null};
show=function(newStep,validate=true){if(newStep>step&&validate){var invalid=validateStep(step);if(invalid){var field=document.getElementById(invalid)||document.querySelector('[name="content_type"]')||document.querySelector('.wizard-platform-card:not(.d-none)');field?.focus();return}}step=newStep;document.querySelectorAll('.wizard-step').forEach(section=>section.classList.toggle('d-none',+section.dataset.step!==step));document.querySelectorAll('.wizard-progress-item').forEach(item=>item.classList.toggle('active',+item.dataset.progress<=step));document.getElementById('previous-step').classList.toggle('d-none',step===1);document.getElementById('next-step').classList.toggle('d-none',step===6);document.getElementById('submit-post').classList.toggle('d-none',step!==6);if(step===6)review();window.scrollTo({top:0,behavior:'smooth'})};
renderInstagramContentType();
</script>
<script>
// Keep every selected asset visible in both the composer and final review preview.
let previewUrl = '';
media.addEventListener('change', () => renderMediaPreview([...media.files]));
window.addEventListener('beforeunload', () => previewUrls.forEach(URL.revokeObjectURL));
</script>
@endpush
